#include <stdio.h>
#include <stdint.h>

static inline int countTrailingZeros(uint64_t n) {
    int cnt = 0;
    while ((n & 1ULL) == 0ULL) {
        n >>= 1;
        ++cnt;
    }
    return cnt;
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        uint64_t N;
        scanf("%llu", &N);
        if (N == 1) {
            printf("0\n");
            continue;
        }
        if (N & 1ULL) {
            printf("1\n");
            continue;
        }
        int v2 = countTrailingZeros(N);
        if (v2 % 2 == 1) {
            printf("-1\n");
            continue;
        }
        uint64_t oddPart = N >> v2;
        if (oddPart == 1ULL) {
            printf("1\n");
        } else {
            printf("2\n");
        }
    }
    return 0;
}

