#!/usr/bin/env python3
import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        N = int(next(it))
        if N == 1:
            out.append('0')
            continue
        if N & 1:
            out.append('1')
            continue
        # count trailing zeros
        v2 = (N & -N).bit_length() - 1  # exponent of lowest set bit
        if v2 % 2 == 1:
            out.append('-1')
            continue
        odd = N >> v2
        if odd == 1:
            out.append('1')
        else:
            out.append('2')
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

