  let temp = N;
  while ((temp & 1n) === 0n) { temp >>= 1n; v2++; }
  if (v2 % 2 === 1) { out.push('-1'); continue; }
  const odd = N >> BigInt(v2);
  if (odd === 1n) out.push('1'); else out.push('2');
